14	struct ContentView: View {
15	    @Environment(\.modelContext) private var context
16	    @Environment(\.undoManager) private var undoManager
17	
18	    @Query(sort: [SortDescriptor(\Contact.lastName), SortDescriptor(\Contact.firstName)])
19	    private var contacts: [Contact]
20	
21	    @Query(sort: \ContactGroup.name) private var groups: [ContactGroup]
22	
23	    @State private var sidebarSelection: SidebarItem? = .allContacts
24	    @State private var selectedContact: Contact?
25	    // Internal so the import handlers in `ContentView+Import.swift` can
26	    // set this when a parse/insert fails.
27	    @State var errorMessage: String?
28	    @State private var searchText = ""
29	    @AppStorage("contactSortOrder") private var sortOrder: ContactSortOrder = .lastName
30	    @AppStorage("defaultGroupID") private var defaultGroupID: String = ""
31	
32	    @State private var isImportingVCard = false
33	    @State private var isImportingCSV = false
34	    @State private var isExportingVCard = false
35	    @State private var exportDocument = VCardDocument(text: "")
36	    @State private var showingDuplicates = false
37	
38	    /// Internal so the import handlers in `ContentView+Import.swift` can
39	    /// reach the same store the main view uses.
40	    var store: ContactStore { ContactStore(context) }
41	
42	    /// The group backing the current sidebar selection, if any.
43	    private var selectedGroup: ContactGroup? {
44	        guard case .group(let id) = sidebarSelection else { return nil }
45	        return groups.first { $0.persistentModelID == id }
46	    }
47	
48	    /// User-configured default group for new contacts when the sidebar is
49	    /// on All Contacts. Resolved by encoded `PersistentIdentifier` so it
50	    /// survives a rename; if the target group was deleted the lookup
51	    /// returns nil and SettingsView prunes the preference on next view.
52	    private var defaultGroup: ContactGroup? {
53	        guard let id = PersistentIdentifier.decode(stored: defaultGroupID) else { return nil }
54	        return groups.first { $0.persistentModelID == id }
55	    }
56	
57	    /// Where a new contact should land. The default group is only used when
58	    /// the sidebar is explicitly on All Contacts — never as a silent rescue
59	    /// from a `.group(...)` selection whose target was deleted, which would
60	    /// surprise the user by adding their contact to an unrelated group.
61	    private var groupForNewContact: ContactGroup? {
62	        switch sidebarSelection {
63	        case .group: selectedGroup
64	        case .allContacts, .none: defaultGroup
65	        }
66	    }
